"""
PDF 转文本工具
用于将 PDF 文件转换为纯文本
"""
import sys
import subprocess
import os

def pdf_to_text(pdf_path, output_path):
    """将 PDF 转换为文本"""
    try:
        # 使用 pdftotext 命令
        result = subprocess.run(
            ['pdftotext', '-layout', pdf_path, output_path],
            capture_output=True,
            text=True
        )

        if result.returncode == 0:
            return True, output_path
        else:
            return False, None
    except Exception as e:
        return False, str(e)

def main():
    if len(sys.argv) < 3:
        print("用法：pdf_to_text.py <输入 PDF> <输出文本>")
        sys.exit(1)

    pdf_path = sys.argv[1]
    output_path = sys.argv[2]

    if not os.path.exists(pdf_path):
        print(f"错误：文件不存在 {pdf_path}")
        sys.exit(1)

    print(f"正在转换：{pdf_path}")
    print(f"输出到：{output_path}")

    success, result = pdf_to_text(pdf_path, output_path)

    if success:
        print(f"✓ 转换成功：{result}")
        print(f"  文件大小：{os.path.getsize(result)} 字节")
    else:
        print(f"✗ 转换失败：{result}")
        sys.exit(1)

if __name__ == "__main__":
    main()

