            });
        }

        // 更新状态栏
        function updateStatusBar() {
            // 计算总向量数（所有文档的分块总数）
            const totalVectors = documents.reduce((sum, doc) => sum + (doc.chunks || 0), 0);
            document.getElementById('faissCount').textContent = `${totalVectors} 个向量`;
            document.getElementById('docCount').textContent = `${documents.length} 个`;
        }

        // 拖拽上传
        const uploadArea = document.getElementById('uploadArea');
        const fileInput = document.getElementById('fileInput');

        uploadArea.addEventListener('dragover', (e) => {
            e.preventDefault();
            uploadArea.classList.add('dragover');
        });

        uploadArea.addEventListener('dragleave', () => {
            uploadArea.classList.remove('dragover');
        });

        uploadArea.addEventListener('drop', (e) => {
            e.preventDefault();
            uploadArea.classList.remove('dragover');
            handleFile(e.dataTransfer.files[0]);
        });

        fileInput.addEventListener('change', (e) => {
            if (e.target.files.length > 0) {
                handleFile(e.target.files[0]);
            }
        });

        // 处理文件上传
        async function handleFile(file) {
            if (!file) return;

            const formData = new FormData();
            formData.append('file', file);

            try {
                const response = await fetch(`${API_BASE}/upload`, {
                    method: 'POST',
                    headers: {
                        'Authorization': 'Bearer sk-123456789abcdef'
                    },
                    body: formData
                });

                const data = await response.json();

                if (data.success) {
                    alert(`上传成功：${file.name}\n大小：${(file.size / 1024).toFixed(2)} KB\n分块数：${data.chunks}`);
                    loadDocuments(); // 从服务器获取最新文档列表
                } else {
                    alert('上传失败：' + data.error);
                }
            } catch (error) {
                console.error('上传失败:', error);
                alert('上传失败，请检查网络连接或服务状态。');
            }
        }

        // 初始化
        loadDocuments();
        checkHealth();

        // 每 10 秒检查一次服务状态
        setInterval(checkHealth, 10000);
    </script>
